import { NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import fs from "fs";
import path from "path";
import nodemailer from "nodemailer";
import Tesseract from "tesseract.js";
import sharp from "sharp";
import poppler from "pdf-poppler"

export const config = {
  api: {
    bodyParser: false,
  },
};

// Directory to store files
const uploadDir = path.join(process.cwd(), "public/uploads");
if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

// Function to save PDF
const saveFile = async (file: File) => {
  const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
  const filePath = path.join(uploadDir, fileName);

  const bytes = await file.arrayBuffer();
  const buffer = Buffer.from(bytes);

  await writeFile(filePath, buffer);
  return filePath;
};

// Function to convert PDF to images
const convertPDFToImages = async (pdfPath: string) => {
  const outputDir = pdfPath.replace(".pdf", "");
  const opts = {
    format: "png",
    out_dir: path.dirname(pdfPath),
    out_prefix: path.basename(outputDir),
    page: null, // Convert all pages
  };

  await poppler.convert(pdfPath, opts);

  const imageFiles = fs
    .readdirSync(path.dirname(pdfPath))
    .filter(
      (file) =>
        file.startsWith(path.basename(outputDir)) && file.endsWith(".png")
    )
    .map((file) => path.join(path.dirname(pdfPath), file));

  return imageFiles;
};

// Function to preprocess image for better OCR accuracy
const preprocessImage = async (imagePath: string) => {
  const processedImage = `${imagePath.replace(".png", "_processed.png")}`;

  await sharp(imagePath).grayscale().normalize().toFile(processedImage);

  return processedImage;
};

// Function to perform OCR
const performOCR = async (imagePath: string) => {
  const { data } = await Tesseract.recognize(imagePath, "eng", {
    logger: (m) => console.log(m),
  });

  return data.text;
};

// Nodemailer setup
const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST,
  port: Number(process.env.EMAIL_PORT),
  secure: process.env.EMAIL_PORT === "465",
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS,
  },
});

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const email = formData.get("email") as string;
    const file = formData.get("marksheet") as File;

    console.log(formData);
    

    if (!file) {
      return NextResponse.json(
        { error: "Marksheet file is required" },
        { status: 400 }
      );
    }

    if (!file.name.toLowerCase().endsWith(".pdf")) {
      return NextResponse.json(
        { error: "Marksheet must be a PDF" },
        { status: 400 }
      );
    }

    // Save PDF file
    const pdfPath = await saveFile(file);
    console.log("PDF saved at:", pdfPath);

    // Convert PDF to images
    const imagePaths = await convertPDFToImages(pdfPath);
    console.log("Converted images:", imagePaths);

    let extractedText = "";

    // Perform OCR on each page
    for (const imagePath of imagePaths) {
      const processedImage = await preprocessImage(imagePath);
      const pageText = await performOCR(processedImage);
      extractedText += pageText + "\n";

      // Cleanup processed images
      fs.unlinkSync(processedImage);
    }

    console.log("Extracted Text:", extractedText);

    // Send Email with extracted marks
    await transporter.sendMail({
      from: process.env.EMAIL_USER,
      to: email,
      subject: "Extracted Marks from PDF",
      html: `<p>Your extracted text from the marksheet is:<br> ${extractedText}</p>`,
    });

    return NextResponse.json(
      { message: "OCR completed successfully", extractedText },
      { status: 201 }
    );
  } catch (error) {
    console.error("Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}
